var sepPort = chrome.runtime.connect({ name: "search_engine_parser" });
let shContent = [];
function sepOnWindowLoad() {
    let e = document.querySelector("title");
    if (e) {
        if (-1 != document.location.hostname.indexOf("youtube")) {
            var t = document.title.toString();
            new MutationObserver(function (e) {
                e.some(function (e) {
                    var n = e.target.textContent.toString();
                    (n = (n = n.replace(/^\([0-9]{0,}\)\s/, "")).replace(/ +/g, " ")) != t &&
                        -1 != document.URL.indexOf("results?search_query") &&
                        (searchFlaggedData(n), (t = n));
                });
            }).observe(e, { subtree: !0, characterData: !0, childList: !0 });
        }
        sepCheckTitle(e);
    } else setTimeout(bingIssueFix, 2e3);
}
function bingIssueFix() {
    if (-1 != document.location.hostname.indexOf("bing")) {
        let e = document.querySelector("input[type=search]");
        if (e && "" != e.value) {
            return void searchFlaggedData(e.value + " - bing");
        }
    }
}
function sepCheckTitle(e) {
    if (e && (!e.text || "" == e.text)) return;
    let t = e.text;
    if (-1 != document.location.hostname.indexOf("youtube")) {
        let e = /^\([0-9]{0,}\)\s/;
        t = (t = t.replace(e, "")).replace(/ +/g, " ");
    } else -1 != document.location.hostname.indexOf("bing") && (t = t.toLowerCase().replace(" - search", " - bing"));
    searchFlaggedData(t);
}
function searchFlaggedData(e) {
    let t = !1;
    for (let n = 0; n < shContent.length; n++) {
        if (-1 != e.toLowerCase().indexOf("google")) {
            let o = document.querySelector("div#taw");
            if (o && ((indexStr = o.innerHTML.toLowerCase().indexOf(shContent[n].toLowerCase())), -1 != indexStr)) {
                let a = Array.from(o.getElementsByTagName("a")),
                    r = a.length > 0 ? a[0].href : "";
                t ||
                    sendSHData(
                        e.toLowerCase().replace("- google search", "").trim(),
                        r,
                        shContent[n],
                        sepCleanDomainName(document.domain)
                    ),
                    (t = !0);
            }
        } else if (-1 != e.toLowerCase().indexOf("bing")) {
            let o = document.querySelector("li.b_ans.b_top");
            if (o && ((indexStr = o.innerHTML.toLowerCase().indexOf(shContent[n].toLowerCase())), -1 != indexStr)) {
                let a = Array.from(o.getElementsByTagName("a")),
                    r = a.length > 0 ? a[0].href : "";
                t ||
                    sendSHData(
                        e.toLowerCase().replace("- bing", "").trim(),
                        r,
                        shContent[n],
                        sepCleanDomainName(document.domain)
                    ),
                    (t = !0);
            }
        } else if (-1 != e.toLowerCase().indexOf("yahoo search")) {
            let o = document.querySelector("div#results div#main li.first");
            if (o && ((indexStr = o.innerHTML.toLowerCase().indexOf(shContent[n].toLowerCase())), -1 != indexStr)) {
                let a = Array.from(o.getElementsByTagName("a")),
                    r = a.length > 0 ? a[0].href : "";
                t ||
                    sendSHData(
                        e.toLowerCase().replace("- yahoo search results", "").trim(),
                        r,
                        shContent[n],
                        sepCleanDomainName(document.domain)
                    ),
                    (t = !0);
            }
        } else if (-1 != e.toLowerCase().indexOf("- youtube")) {
            let o = document.querySelector("ytd-emergency-onebox-renderer");
            if (o && ((indexStr = o.innerHTML.toLowerCase().indexOf(shContent[n].toLowerCase())), -1 != indexStr)) {
                let a = Array.from(o.getElementsByTagName("a")),
                    r = a.length > 0 ? a[0].href : "";
                t ||
                    sendSHData(
                        e.toLowerCase().replace("- youtube", "").trim(),
                        r,
                        shContent[n],
                        sepCleanDomainName(document.domain)
                    ),
                    (t = !0);
            }
        }
        if (t) break;
    }
}
function restrictYoutubePreview(e) {
    const t = e.querySelectorAll("div[data-vid]:not([data-ryp-processed])");
    0 !== t.length &&
        t.forEach((e) => {
            e.setAttribute("data-ryp-processed", "true");
            const t = e.querySelector("[data-vll]");
            t && (t.style.pointerEvents = "none");
        });
}
function initGoogleYoutubeRestrictions() {
    if (-1 === document.location.hostname.indexOf(".google.") || !document.location.pathname.startsWith("/search"))
        return;
    const e = document.querySelector("div#center_col");
    e &&
        (restrictYoutubePreview(e),
        new MutationObserver(() => {
            restrictYoutubePreview(e);
        }).observe(e, { childList: !0, subtree: !0 }));
}
function sepSendData(e) {
    sepPort.postMessage({ action: "fetchResult" });
}
function sendSHData(e, t, n, o) {
    sepPort.postMessage({ action: "sendSHResult", msg: e, url: t, matchedTerm: n, domain: o });
}
function sepCleanDomainName(e) {
    return e.replace(/^(?:https?:\/\/)?(?:www\.)?/i, "");
}
function sepCallWindowLoadWithTimeOut() {
    initGoogleYoutubeRestrictions(), sepSendData(), setTimeout(sepOnWindowLoad, 2e3);
}
function handleYoutubePreviewModeRedirectsTopCard(e) {
    if (-1 === document.location.hostname.indexOf(".google.") || !document.location.pathname.startsWith("/search"))
        return;
    const t = e.target.closest('[data-attrid="VisualDigestVideoResult"]');
    if (!t) return;
    if (e.target.closest("a[href]")) return;
    const n = t.querySelector("[data-curl]"),
        o = n && n.dataset && n.dataset.curl;
    o && (e.preventDefault(), e.stopImmediatePropagation(), (window.location.href = o));
}
function handleVideoRedirectSearchResult(e) {
    if (-1 === document.location.hostname.indexOf(".google.") || !document.location.pathname.startsWith("/search"))
        return;
    const t = e.target.closest("div[data-vid]");
    if (!t) return;
    if (!t.closest("#center_col")) return;
    if (e.target.closest("a[href]")) return;
    const n = t.dataset && t.dataset.curl;
    n && (e.preventDefault(), e.stopImmediatePropagation(), (window.location.href = n));
}
sepPort.onMessage.addListener(function (e) {
    shContent = e;
}),
    window.addEventListener
        ? window.addEventListener("load", sepCallWindowLoadWithTimeOut, !1)
        : window.attachEvent && window.attachEvent("onload", sepCallWindowLoadWithTimeOut),
    document.addEventListener("click", handleYoutubePreviewModeRedirectsTopCard, !0),
    document.addEventListener(
        "keydown",
        (e) => {
            ("Enter" !== e.key && " " !== e.key) || handleYoutubePreviewModeRedirectsTopCard(e);
        },
        !0
    ),
    document.addEventListener(
        "keydown",
        (e) => {
            ("Enter" !== e.key && " " !== e.key) || handleVideoRedirectSearchResult(e);
        },
        !0
    );
